  const client = new Client({
    token: 'YOUR_TOKEN',
  });

  const inboxToken: InboxToken = {
    connectionId: 'connection_id',
    token: 'ipsum nulla mag',
  };

  const { data } = await client.channels.saveInboxToken(inboxToken);

  console.log(data);
})();
```

